import type { Metadata } from "next"
import { BookingApp } from "./BookingApp"

export const metadata: Metadata = {
  title: "国内線フライト予約 | Gunjo Air",
  description: "便を検索して座席を選び、運賃を確認してから予約する国内線の予約フロー。",
}

// Server Component shell. All interactive logic (and every function prop —
// onValueChange, onSelect, formatters) lives behind the "use client" boundary
// in BookingApp, so `next build` doesn't choke on serializing functions.
export default function FlightBookingPage() {
  return (
    <main className="min-h-screen bg-muted/30">
      <BookingApp />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  IconArrowsExchange,
  IconPlane,
  IconClock,
  IconArrowRight,
  IconUser,
  IconArmchair,
  IconLuggage,
  IconCheck,
  IconChevronLeft,
} from "@tabler/icons-react"
import {
  Stepper,
  type StepperStep,
  ListCard,
  Badge,
  Button,
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Select,
  NumberInput,
  Input,
  RadioGroup,
  RadioGroupItem,
  AmountBreakdown,
  type AmountLine,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
} from "@gunjo/ui"
import {
  AIRPORTS,
  FLIGHTS,
  FARE_KINDS,
  AIRPORT_FEE,
  PFC,
  FUEL_SURCHARGE,
  buildSeatMap,
  formatJPY,
  formatDuration,
  type Flight,
  type FareKind,
  type SeatClass,
  type PassengerCounts,
} from "./flight-data"
import { SeatMap } from "./SeatMap"

type Step = "flight" | "seat" | "passenger" | "review" | "payment"

const STEP_ORDER: Step[] = ["flight", "seat", "passenger", "review", "payment"]
const STEP_LABELS: Record<Step, string> = {
  flight: "便選択",
  seat: "座席指定",
  passenger: "搭乗者",
  review: "確認",
  payment: "決済",
}

function carrierBadge(carrier: Flight["carrier"]) {
  return carrier === "ANA" ? (
    <Badge variant="info">ANA</Badge>
  ) : (
    <Badge variant="destructive">JAL</Badge>
  )
}

function flightTags(flight: Flight) {
  if (!flight.tags?.length) return undefined
  const map: Record<NonNullable<Flight["tags"]>[number], { label: string; variant: "success" | "warning" | "secondary" }> = {
    fastest: { label: "最速", variant: "success" },
    cheapest: { label: "最安", variant: "warning" },
    recommended: { label: "おすすめ", variant: "secondary" },
  }
  return (
    <>
      {flight.tags.map((t) => (
        <Badge key={t} variant={map[t].variant}>
          {map[t].label}
        </Badge>
      ))}
    </>
  )
}

export function BookingApp() {
  // ---- search criteria ----
  const [from, setFrom] = React.useState("HND")
  const [to, setTo] = React.useState("CTS")
  const [date, setDate] = React.useState("2026-07-15")
  const [fareKind, setFareKind] = React.useState<FareKind>("value")
  const [seatClass, setSeatClass] = React.useState<SeatClass>("ordinary")

  // ---- passengers ----
  const [pax, setPax] = React.useState<PassengerCounts>({ adult: 1, child: 0, infant: 0 })
  const [names, setNames] = React.useState<{ family: string; given: string }[]>([
    { family: "", given: "" },
  ])
  const [useMiles, setUseMiles] = React.useState(false)

  // ---- selection ----
  const [step, setStep] = React.useState<Step>("flight")
  const [selectedFlightId, setSelectedFlightId] = React.useState<string | null>(null)
  const [selectedSeats, setSelectedSeats] = React.useState<string[]>([])

  const selectedFlight = React.useMemo(
    () => FLIGHTS.find((f) => f.id === selectedFlightId) ?? null,
    [selectedFlightId]
  )
  const seatMap = React.useMemo(
    () => (selectedFlight ? buildSeatMap(selectedFlight.aircraft) : null),
    [selectedFlight]
  )

  const seatedPax = pax.adult + pax.child // 幼児は座席なし
  const totalPax = seatedPax + pax.infant

  // keep names array length in sync with seated passenger count
  React.useEffect(() => {
    setNames((prev) => {
      const next = [...prev]
      while (next.length < seatedPax) next.push({ family: "", given: "" })
      next.length = seatedPax
      return next
    })
  }, [seatedPax])

  const swap = () => {
    setFrom(to)
    setTo(from)
  }

  const handleToggleSeat = (seatId: string) => {
    setSelectedSeats((prev) =>
      prev.includes(seatId) ? prev.filter((s) => s !== seatId) : [...prev, seatId]
    )
  }

  // ---- fare math ----
  const fareInfo = React.useMemo(() => {
    if (!selectedFlight) return null
    const fareForClass =
      selectedFlight.fares.find((f) => f.seatClass === seatClass) ?? selectedFlight.fares[0]
    const unitFare = fareForClass.prices[fareKind]

    const baseFare = unitFare * pax.adult + Math.round(unitFare * 0.5) * pax.child // 小児は約50%
    const airportFee = AIRPORT_FEE * seatedPax
    const pfc = PFC * seatedPax
    const seatFee =
      seatMap != null
        ? selectedSeats.reduce((sum, id) => sum + (seatMap.seats[id]?.fee ?? 0), 0)
        : 0
    const milesDiscount = useMiles ? Math.min(3000, Math.round(baseFare * 0.1)) : 0
    const saverDiscount = fareKind === "saver" ? Math.round(baseFare * 0.05) : 0
    const total = baseFare + airportFee + pfc + FUEL_SURCHARGE + seatFee - milesDiscount - saverDiscount
    return {
      fareForClass,
      unitFare,
      baseFare,
      airportFee,
      pfc,
      seatFee,
      milesDiscount,
      saverDiscount,
      total,
    }
  }, [selectedFlight, seatClass, fareKind, pax, seatedPax, seatMap, selectedSeats, useMiles])

  // ---- stepper ----
  const stepperSteps: StepperStep[] = STEP_ORDER.map((s) => ({
    label: STEP_LABELS[s],
    state:
      s === step
        ? "current"
        : STEP_ORDER.indexOf(s) < STEP_ORDER.indexOf(step)
          ? "completed"
          : "upcoming",
  }))

  const goNext = () => {
    const i = STEP_ORDER.indexOf(step)
    if (i < STEP_ORDER.length - 1) setStep(STEP_ORDER[i + 1])
  }
  const goBack = () => {
    const i = STEP_ORDER.indexOf(step)
    if (i > 0) setStep(STEP_ORDER[i - 1])
  }

  const fareKindLabel = FARE_KINDS.find((f) => f.id === fareKind)?.label ?? ""

  // amount-breakdown lines (shared by review + payment)
  const breakdownLines: AmountLine[] = fareInfo
    ? [
        { type: "heading", label: "運賃" },
        {
          label: `${fareInfo.fareForClass.label}（${fareKindLabel}）× 大人${pax.adult}`,
          amount: fareInfo.unitFare * pax.adult,
          note: `単価 ${formatJPY(fareInfo.unitFare)}`,
        },
        ...(pax.child > 0
          ? [
              {
                label: `小児運賃 × ${pax.child}`,
                amount: Math.round(fareInfo.unitFare * 0.5) * pax.child,
                note: "大人運賃の約50%",
              } as AmountLine,
            ]
          : []),
        { type: "heading", label: "諸税・料金" },
        { label: `空港使用料 × ${seatedPax}`, amount: fareInfo.airportFee },
        { label: `旅客施設使用料（PFC）× ${seatedPax}`, amount: fareInfo.pfc },
        { label: "燃油サーチャージ（国内線）", amount: FUEL_SURCHARGE },
        {
          label: `座席指定料 ${selectedSeats.length > 0 ? `（${selectedSeats.join("・")}）` : ""}`,
          amount: fareInfo.seatFee,
        },
        ...(fareInfo.saverDiscount > 0
          ? [
              {
                type: "heading",
                label: "割引",
              } as AmountLine,
              {
                label: "特割",
                amount: fareInfo.saverDiscount,
                kind: "subtract",
              } as AmountLine,
            ]
          : []),
        ...(fareInfo.milesDiscount > 0
          ? [
              ...(fareInfo.saverDiscount > 0 ? [] : [{ type: "heading", label: "割引" } as AmountLine]),
              {
                label: "マイル利用",
                amount: fareInfo.milesDiscount,
                kind: "subtract",
                note: "10% 上限3,000円",
              } as AmountLine,
            ]
          : []),
      ]
    : []

  return (
    <div className="mx-auto flex w-full max-w-md flex-col gap-4 px-4 pb-28 pt-4">
      {/* Header */}
      <header className="flex items-center gap-2">
        <IconPlane className="h-6 w-6 text-primary" aria-hidden="true" />
        <h1 className="text-lg font-bold text-foreground">国内線予約</h1>
      </header>

      {/* Progress */}
      <Card>
        <Stepper steps={stepperSteps} className="!p-3" aria-label="予約ステップ" />
      </Card>

      {/* ---------------------------------------------------------------- */}
      {step === "flight" && (
        <FlightStep
          from={from}
          to={to}
          date={date}
          fareKind={fareKind}
          seatClass={seatClass}
          pax={pax}
          onSwap={swap}
          onFrom={setFrom}
          onTo={setTo}
          onDate={setDate}
          onFareKind={setFareKind}
          onSeatClass={setSeatClass}
          onSelectFlight={(id) => {
            setSelectedFlightId(id)
            setSelectedSeats([])
            goNext()
          }}
        />
      )}

      {step === "seat" && selectedFlight && seatMap && (
        <div className="flex flex-col gap-4">
          <SelectedFlightSummary flight={selectedFlight} />
          <Card>
            <CardHeader className="!p-4 !pb-2">
              <CardTitle as="h2" className="flex items-center gap-2 !text-base">
                <IconArmchair className="h-5 w-5 text-primary" aria-hidden="true" />
                座席指定
              </CardTitle>
            </CardHeader>
            <CardContent className="!p-4 !pt-0">
              {seatedPax > 1 && (
                <Alert variant="info" className="mb-3">
                  <AlertTitle>{seatedPax}名分の座席をお選びください</AlertTitle>
                  <AlertDescription>
                    選択済み {selectedSeats.length} / {seatedPax} 席
                  </AlertDescription>
                </Alert>
              )}
              <SeatMap
                seatMap={seatMap}
                selectedSeats={selectedSeats}
                maxSeats={seatedPax}
                onToggleSeat={handleToggleSeat}
              />
            </CardContent>
          </Card>
        </div>
      )}

      {step === "passenger" && (
        <PassengerStep
          pax={pax}
          names={names}
          useMiles={useMiles}
          onPax={setPax}
          onName={(idx, field, value) =>
            setNames((prev) => prev.map((n, i) => (i === idx ? { ...n, [field]: value } : n)))
          }
          onUseMiles={setUseMiles}
        />
      )}

      {step === "review" && selectedFlight && fareInfo && (
        <ReviewStep
          flight={selectedFlight}
          fareKindLabel={fareKindLabel}
          seatClassLabel={fareInfo.fareForClass.label}
          selectedSeats={selectedSeats}
          names={names}
          pax={pax}
          breakdownLines={breakdownLines}
          total={fareInfo.total}
        />
      )}

      {step === "payment" && selectedFlight && fareInfo && (
        <div className="flex flex-col gap-4">
          <Alert variant="success">
            <AlertTitle className="flex items-center gap-2">
              <IconCheck className="h-4 w-4" aria-hidden="true" /> 予約内容を確定する準備ができました
            </AlertTitle>
            <AlertDescription>
              お支払い方法を選択して決済に進みます（このデモでは決済は実行されません）。
            </AlertDescription>
          </Alert>
          <Card>
            <CardContent className="!p-4">
              <AmountBreakdown
                lines={breakdownLines}
                total={{ label: "お支払い総額", amount: fareInfo.total }}
                formula="お支払い総額 = 運賃 ＋ 諸税・料金 ＋ 座席指定料 − 割引"
              />
            </CardContent>
          </Card>
        </div>
      )}

      {/* ---------- sticky footer nav ---------- */}
      <FooterBar
        step={step}
        canProceed={canProceed(step, {
          selectedFlightId,
          selectedSeats,
          seatedPax,
          names,
        })}
        total={fareInfo?.total}
        onBack={goBack}
        onNext={goNext}
      />
    </div>
  )
}

// ---------------------------------------------------------------------------

function canProceed(
  step: Step,
  ctx: {
    selectedFlightId: string | null
    selectedSeats: string[]
    seatedPax: number
    names: { family: string; given: string }[]
  }
): boolean {
  switch (step) {
    case "flight":
      return ctx.selectedFlightId != null
    case "seat":
      return ctx.selectedSeats.length === ctx.seatedPax
    case "passenger":
      return ctx.names.every((n) => n.family.trim() && n.given.trim())
    case "review":
      return true
    case "payment":
      return true
  }
}

function FooterBar({
  step,
  canProceed,
  total,
  onBack,
  onNext,
}: {
  step: Step
  canProceed: boolean
  total?: number
  onBack: () => void
  onNext: () => void
}) {
  const isFirst = step === "flight"
  const isPayment = step === "payment"
  const nextLabel =
    step === "review" ? "決済へ進む" : isPayment ? "予約を確定する" : "次へ"
  return (
    <div className="fixed inset-x-0 bottom-0 z-20 border-t border-border bg-background/95 backdrop-blur">
      <div className="mx-auto flex w-full max-w-md items-center gap-3 px-4 py-3">
        {!isFirst && (
          <Button variant="outline" size="lg" onClick={onBack} aria-label="前のステップへ戻る">
            <IconChevronLeft className="h-4 w-4" aria-hidden="true" />
            戻る
          </Button>
        )}
        {total != null && (
          <div className="flex flex-col leading-none">
            <span className="text-[10px] text-muted-foreground">お支払い総額</span>
            <span className="text-base font-bold tabular-nums text-foreground">
              {formatJPY(total)}
            </span>
          </div>
        )}
        <Button
          variant="primary"
          size="lg"
          className="ml-auto"
          disabled={!canProceed}
          onClick={onNext}
        >
          {nextLabel}
          {!isPayment && <IconArrowRight className="h-4 w-4" aria-hidden="true" />}
        </Button>
      </div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Flight search + result list
// ---------------------------------------------------------------------------

function FlightStep({
  from,
  to,
  date,
  fareKind,
  seatClass,
  pax,
  onSwap,
  onFrom,
  onTo,
  onDate,
  onFareKind,
  onSeatClass,
  onSelectFlight,
}: {
  from: string
  to: string
  date: string
  fareKind: FareKind
  seatClass: SeatClass
  pax: PassengerCounts
  onSwap: () => void
  onFrom: (v: string) => void
  onTo: (v: string) => void
  onDate: (v: string) => void
  onFareKind: (v: FareKind) => void
  onSeatClass: (v: SeatClass) => void
  onSelectFlight: (id: string) => void
}) {
  const paxLabel = `大人${pax.adult}${pax.child ? `・小児${pax.child}` : ""}${
    pax.infant ? `・幼児${pax.infant}` : ""
  }`
  return (
    <div className="flex flex-col gap-4">
      {/* Search criteria */}
      <Card>
        <CardContent className="!p-4">
          <div className="flex items-end gap-2">
            <Select
              label="出発地"
              value={from}
              onChange={(e) => onFrom(e.target.value)}
              className="flex-1"
            >
              {Object.values(AIRPORTS).map((a) => (
                <option key={a.code} value={a.code} disabled={a.code === to}>
                  {a.name}（{a.code}）
                </option>
              ))}
            </Select>
            <Button
              variant="outline"
              size="icon"
              onClick={onSwap}
              aria-label="出発地と到着地を入れ替える"
              className="mb-0.5 shrink-0"
            >
              <IconArrowsExchange className="h-4 w-4" aria-hidden="true" />
            </Button>
            <Select
              label="到着地"
              value={to}
              onChange={(e) => onTo(e.target.value)}
              className="flex-1"
            >
              {Object.values(AIRPORTS).map((a) => (
                <option key={a.code} value={a.code} disabled={a.code === from}>
                  {a.name}（{a.code}）
                </option>
              ))}
            </Select>
          </div>

          <div className="mt-3 grid grid-cols-2 gap-2">
            <Input
              type="date"
              label="搭乗日"
              value={date}
              onChange={(e) => onDate(e.target.value)}
            />
            <Select
              label="クラス"
              value={seatClass}
              onChange={(e) => onSeatClass(e.target.value as SeatClass)}
            >
              <option value="ordinary">普通席</option>
              <option value="premium">プレミアム / 上位クラス</option>
            </Select>
          </div>

          <div className="mt-3">
            <span className="text-sm font-medium text-foreground">運賃種別</span>
            <RadioGroup
              value={fareKind}
              onValueChange={(v) => onFareKind(v as FareKind)}
              className="mt-2 flex flex-col gap-2"
              aria-label="運賃種別"
            >
              {FARE_KINDS.map((fk) => (
                <RadioGroupItem
                  key={fk.id}
                  value={fk.id}
                  label={fk.label}
                  description={fk.note}
                />
              ))}
            </RadioGroup>
          </div>

          <p className="mt-3 text-xs text-muted-foreground">搭乗者 {paxLabel}</p>
        </CardContent>
      </Card>

      {/* Result list header */}
      <div className="flex items-baseline justify-between">
        <h2 className="text-sm font-semibold text-foreground">
          {AIRPORTS[from]?.name} → {AIRPORTS[to]?.name}
        </h2>
        <span className="text-xs text-muted-foreground">{FLIGHTS.length}件の便</span>
      </div>

      {/* Flight result list — ListCard, the kit's tappable result-row primitive */}
      <ul className="flex flex-col gap-2" aria-label="フライト検索結果">
        {FLIGHTS.map((flight) => {
          const fare = flight.fares.find((f) => f.seatClass === seatClass) ?? flight.fares[0]
          const price = fare.prices[fareKind]
          const low = flight.seatsLeft <= 5
          return (
            <li key={flight.id}>
              <ListCard
                onSelect={() => onSelectFlight(flight.id)}
                severity={low ? "warning" : undefined}
                leading={
                  <div className="flex w-12 flex-col items-center gap-1">
                    {carrierBadge(flight.carrier)}
                    <span className="text-[10px] font-semibold tabular-nums text-muted-foreground">
                      {flight.flightNo}
                    </span>
                  </div>
                }
                title={
                  <span className="flex items-center gap-1.5 text-base tabular-nums">
                    {flight.departure}
                    <IconArrowRight className="h-3.5 w-3.5 text-muted-foreground" aria-hidden="true" />
                    {flight.arrival}
                  </span>
                }
                description={
                  <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                    <span className="inline-flex items-center gap-0.5">
                      <IconClock className="h-3 w-3" aria-hidden="true" />
                      {formatDuration(flight.durationMin)}
                    </span>
                    <span>
                      {flight.stops === 0 ? "直行" : `経由（${AIRPORTS[flight.via!]?.name}）`}
                    </span>
                    <span>{flight.aircraft}</span>
                  </span>
                }
                tags={
                  <>
                    {flightTags(flight)}
                    <Badge variant={low ? "warning" : "outline"}>残{flight.seatsLeft}席</Badge>
                  </>
                }
                meta={
                  <span className="flex flex-col items-end">
                    <span className="text-base font-bold tabular-nums text-foreground">
                      {formatJPY(price)}
                    </span>
                    <span className="text-[10px] text-muted-foreground">{fare.label}〜</span>
                  </span>
                }
              />
            </li>
          )
        })}
      </ul>
    </div>
  )
}

function SelectedFlightSummary({ flight }: { flight: Flight }) {
  return (
    <Card>
      <CardContent className="!p-4">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-2">
            {carrierBadge(flight.carrier)}
            <span className="text-sm font-semibold tabular-nums">{flight.flightNo}</span>
          </div>
          <span className="text-xs text-muted-foreground">{flight.aircraft}</span>
        </div>
        <div className="mt-2 flex items-center gap-3 tabular-nums">
          <div className="flex flex-col">
            <span className="text-lg font-bold">{flight.departure}</span>
            <span className="text-xs text-muted-foreground">
              {AIRPORTS[flight.from]?.name}（{flight.from}）
            </span>
          </div>
          <div className="flex flex-1 flex-col items-center text-muted-foreground">
            <span className="text-[10px]">{formatDuration(flight.durationMin)}</span>
            <div className="flex w-full items-center gap-1">
              <span className="h-px flex-1 bg-border" />
              <IconPlane className="h-3.5 w-3.5" aria-hidden="true" />
              <span className="h-px flex-1 bg-border" />
            </div>
            <span className="text-[10px]">{flight.stops === 0 ? "直行" : "経由"}</span>
          </div>
          <div className="flex flex-col items-end">
            <span className="text-lg font-bold">{flight.arrival}</span>
            <span className="text-xs text-muted-foreground">
              {AIRPORTS[flight.to]?.name}（{flight.to}）
            </span>
          </div>
        </div>
        {flight.gate && (
          <p className="mt-2 text-xs text-muted-foreground">出発 {flight.gate}番ゲート</p>
        )}
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Passenger step
// ---------------------------------------------------------------------------

function PassengerStep({
  pax,
  names,
  useMiles,
  onPax,
  onName,
  onUseMiles,
}: {
  pax: PassengerCounts
  names: { family: string; given: string }[]
  useMiles: boolean
  onPax: (p: PassengerCounts) => void
  onName: (idx: number, field: "family" | "given", value: string) => void
  onUseMiles: (v: boolean) => void
}) {
  return (
    <div className="flex flex-col gap-4">
      <Card>
        <CardHeader className="!p-4 !pb-2">
          <CardTitle as="h2" className="flex items-center gap-2 !text-base">
            <IconUser className="h-5 w-5 text-primary" aria-hidden="true" />
            搭乗者
          </CardTitle>
        </CardHeader>
        <CardContent className="!p-4 !pt-0">
          <div className="grid grid-cols-3 gap-2">
            <NumberInput
              label="大人"
              layout="stepper"
              min={1}
              max={8}
              value={pax.adult}
              onValueChange={(v) => onPax({ ...pax, adult: v })}
              description="12歳〜"
            />
            <NumberInput
              label="小児"
              layout="stepper"
              min={0}
              max={8}
