// ----- Seat map model -----

export type SeatState = "available" | "occupied" | "selected" | "blocked"
export type SeatType = "standard" | "exit" | "extra-legroom" | "premium"

export interface Seat {
  id: string // e.g. "12A"
  row: number
  col: string // "A".."K"
  state: SeatState
  type: SeatType
  fee: number // 座席指定料 in JPY (0 = 無料)
  window?: boolean // 窓側
  aisle?: boolean // 通路側
}

export interface CabinSection {
  label: string // プレミアムクラス / 普通席
  seatClass: SeatClass
  columns: string[] // includes "" for aisle gaps, e.g. ["A","C","","D","F"]
  rows: number[] // row numbers in this section
}

export interface AircraftSeatMap {
  aircraft: string
  // column layout description, e.g. "3-3" or "2-4-2"
  layoutLabel: string
  sections: CabinSection[]
  seats: Record<string, Seat> // keyed by seat id
}

// Deterministic occupied/blocked pattern so SSR and client render identically
// (no Math.random → no hydration mismatch).
function occupiedPattern(row: number, col: string): boolean {
  const colIndex = col.charCodeAt(0)
  return (row * 7 + colIndex * 3) % 5 === 0
}

// Build a 3-3 narrowbody (B737-800 style) cabin: premium rows 1-3 (2-2), ordinary 10-30 (3-3).
export function buildSeatMap(aircraft: string): AircraftSeatMap {
  const seats: Record<string, Seat> = {}

  // Premium: rows 1-3, columns A C | D F (2-2)
  const premiumCols = ["A", "C", "", "D", "F"]
  const premiumRows = [1, 2, 3]
  for (const row of premiumRows) {
    for (const col of premiumCols) {
      if (!col) continue
      const id = `${row}${col}`
      const occupied = occupiedPattern(row, col)
      seats[id] = {
        id,
        row,
        col,
        state: occupied ? "occupied" : "available",
        type: "premium",
        fee: 0,
        window: col === "A" || col === "F",
        aisle: col === "C" || col === "D",
      }
    }
  }

  // Ordinary: rows 10-30, columns A B C | D E F (3-3)
  const ordinaryCols = ["A", "B", "C", "", "D", "E", "F"]
  const ordinaryRows = Array.from({ length: 21 }, (_, i) => i + 10)
  const exitRows = [14, 15] // 非常口座席（足元ゆったり）
  for (const row of ordinaryRows) {
    for (const col of ordinaryCols) {
      if (!col) continue
      const id = `${row}${col}`
      const occupied = occupiedPattern(row, col)
      const isExit = exitRows.includes(row)
      // first ordinary row (10) = 足元ゆったり (バルクヘッド)
      const isLegroom = row === 10
      let type: SeatType = "standard"
      let fee = 0
      if (isExit) {
        type = "exit"
        fee = 1500
      } else if (isLegroom) {
        type = "extra-legroom"
        fee = 1200
      } else if (col === "A" || col === "F") {
        fee = 600 // 窓側指定料
      } else if (col === "C" || col === "D") {
        fee = 500 // 通路側指定料
      } else {
        fee = 300 // 中央席
      }
      seats[id] = {
        id,
        row,
        col,
        state: occupied ? "occupied" : "available",
        type,
        fee,
        window: col === "A" || col === "F",
        aisle: col === "C" || col === "D",
      }
    }
  }

  return {
    aircraft,
    layoutLabel: "3-3",
    sections: [
      { label: "プレミアムクラス", seatClass: "premium", columns: premiumCols, rows: premiumRows },
      { label: "普通席", seatClass: "ordinary", columns: ordinaryCols, rows: ordinaryRows },
    ],
    seats,
  }
}

