// ---------------------------------------------------------------------------
// SeatMap — HAND-ROLLED. @gunjo/ui ships no 2-D seat-grid primitive (the
// /docs/by-use-case reverse lookup pointed at HeatmapChart, which is a
// read-only data viz, not an interactive picker). Everything here is bespoke:
// the aisle/cabin model, per-seat type + fee, selection state, and the a11y
// (grid roles, keyboard, SR seat names). Built on raw HTML/CSS per the repo's
// "charts use HTML/CSS layout primitives" rule.
// ---------------------------------------------------------------------------

const STATE_CLASSES: Record<SeatState, string> = {
  available: "bg-card border-border text-foreground hover:border-ring hover:bg-muted",
  occupied: "bg-muted border-border text-muted-foreground cursor-not-allowed opacity-60",
  selected: "bg-primary border-primary text-primary-foreground",
  blocked: "bg-muted border-border text-muted-foreground cursor-not-allowed opacity-40",
}

const TYPE_LABEL: Record<SeatType, string> = {
  standard: "普通席",
  exit: "非常口座席（足元ゆったり）",
  "extra-legroom": "足元ゆったり",
  premium: "プレミアムクラス",
}

function seatAccessibleName(seat: Seat): string {
  const parts = [`${seat.row}列${seat.col}`]
  if (seat.window) parts.push("窓側")
  if (seat.aisle) parts.push("通路側")
  parts.push(TYPE_LABEL[seat.type])
  if (seat.state === "occupied") parts.push("予約済み・選択不可")
  else if (seat.state === "selected") parts.push("選択中")
  else parts.push(seat.fee > 0 ? `座席指定料 ${formatJPY(seat.fee)}` : "座席指定料無料")
  return parts.join("、")
}

function SeatButton({
  seat,
  onToggle,
}: {
  seat: Seat
  onToggle: (id: string) => void
}) {
  const disabled = seat.state === "occupied" || seat.state === "blocked"
  return (
    <button
      type="button"
      role="gridcell"
      aria-label={seatAccessibleName(seat)}
      aria-pressed={seat.state === "selected"}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      onClick={() => !disabled && onToggle(seat.id)}
      data-seat-type={seat.type}
      className={[
        "relative flex h-9 w-9 items-center justify-center rounded-md border text-[11px] font-medium tabular-nums transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        STATE_CLASSES[seat.state],
        (seat.type === "exit" || seat.type === "extra-legroom") &&
          seat.state !== "selected" &&
          "ring-1 ring-info-border",
      ]
        .filter(Boolean)
        .join(" ")}
    >
      {seat.col}
    </button>
  )
}

export interface SeatMapProps {
  seatMap: AircraftSeatMap
  selectedSeats: string[]
  /** Max number of seats the user may pick (= number of seated passengers). */
  maxSeats: number
  onToggleSeat: (seatId: string) => void
}

export function SeatMap({ seatMap, selectedSeats, maxSeats, onToggleSeat }: SeatMapProps) {
  const handleToggle = React.useCallback(
    (id: string) => {
      const isSelected = selectedSeats.includes(id)
      if (!isSelected && selectedSeats.length >= maxSeats) return // at capacity
      onToggleSeat(id)
    },
    [selectedSeats, maxSeats, onToggleSeat]
  )

  // resolve live state for each seat (selection overrides stored state)
  const resolve = (seat: Seat): Seat =>
    selectedSeats.includes(seat.id) ? { ...seat, state: "selected" } : seat

  return (
    <div className="flex flex-col gap-4">
      {/* Legend */}
      <div
        className="flex flex-wrap items-center gap-x-4 gap-y-2 text-xs text-muted-foreground"
        aria-hidden="true"
      >
        <span className="flex items-center gap-1.5">
          <span className="h-4 w-4 rounded border border-border bg-card" /> 空席
        </span>
        <span className="flex items-center gap-1.5">
          <span className="h-4 w-4 rounded border border-primary bg-primary" /> 選択中
        </span>
        <span className="flex items-center gap-1.5">
          <span className="h-4 w-4 rounded border border-border bg-muted opacity-60" /> 予約済
        </span>
        <span className="flex items-center gap-1.5">
          <span className="h-4 w-4 rounded border border-info-border ring-1 ring-info-border" />{" "}
          非常口・足元ゆったり
        </span>
      </div>

      {/* Nose / 機首 marker */}
      <div className="flex flex-col items-center text-xs text-muted-foreground">
        <div className="rounded-t-full border-x border-t border-border px-6 pb-1 pt-2">機首 / 前方</div>
      </div>

      <div role="grid" aria-label={`${seatMap.aircraft} 座席表`} className="flex flex-col gap-3">
        {seatMap.sections.map((section, si) => (
          <section key={section.label} aria-label={`${section.label} エリア`} className="flex flex-col gap-2">
            <div className="flex items-center gap-2 text-xs font-medium text-muted-foreground">
              <IconArmchair className="h-3.5 w-3.5" aria-hidden="true" />
              {section.label}
              <span className="text-[10px]">（{section.columns.filter(Boolean).length}列）</span>
            </div>

            {/* Column header (seat letters / aisle gap) */}
            <div role="row" className="flex items-center gap-1.5 pl-7">
              {section.columns.map((col, ci) =>
                col ? (
                  <span
                    key={ci}
                    className="flex h-4 w-9 items-center justify-center text-[10px] text-muted-foreground"
                    aria-hidden="true"
                  >
                    {col}
                  </span>
                ) : (
                  <span key={ci} className="w-5" aria-hidden="true" />
                )
              )}
            </div>

            {section.rows.map((row) => {
              const isExitRow = seatMap.seats[`${row}${section.columns.find(Boolean)}`]?.type === "exit"
              return (
                <div role="row" key={row} className="flex items-center gap-1.5">
                  {/* row number */}
                  <span
                    className="flex w-6 items-center justify-end pr-1 text-[10px] tabular-nums text-muted-foreground"
                    aria-hidden="true"
                  >
                    {row}
                  </span>
                  {section.columns.map((col, ci) => {
                    if (!col) {
                      // aisle gap
                      return (
                        <span
                          key={ci}
                          className="flex w-5 items-center justify-center"
                          aria-hidden="true"
                        >
                          {isExitRow ? (
                            <IconDoor className="h-4 w-4 text-info" aria-hidden="true" />
                          ) : null}
                        </span>
                      )
                    }
                    const seat = seatMap.seats[`${row}${col}`]
                    if (!seat) return <span key={ci} className="h-9 w-9" />
                    return <SeatButton key={ci} seat={resolve(seat)} onToggle={handleToggle} />
                  })}
                  {/* window marker on right edge */}
                  <span className="ml-1 flex w-4 items-center" aria-hidden="true">
                    <IconWindow className="h-3.5 w-3.5 text-muted-foreground/50" />
                  </span>
                </div>
              )
            })}
            {si < seatMap.sections.length - 1 && <Separator className="my-1" />}
          </section>
        ))}
      </div>

      <p className="text-xs text-muted-foreground">
        座席をタップして選択（{maxSeats}席まで）。窓側 A / K・通路側 C / H。非常口座席・足元ゆったりは追加料金がかかります。
      </p>
    </div>
  )
}
